- (void)segmentControlChanged:(HMSegmentedControl *)sender {
    UIViewController *oldViewController = self.childViewControllers.firstObject;
    oldViewController.view.alpha = 1.0; // Make sure the old view is fully visible

    // Get the new view controller
    UIViewController *newViewController = [self.childViewControllers objectAtIndex:sender.selectedSegmentIndex];

    // Animate the transition
    [self transitionFromViewController:oldViewController toViewController:newViewController duration:0.5 options:UIViewAnimationOptionTransitionCrossDissolve animations:^{
        // Fade out the old view
        oldViewController.view.alpha = 0.0;
    } completion:^(BOOL finished) {
